/// Calculate image escrow lockup using model-specific pricing
///
/// This is the amount the user must have locked up when submitting an image call.
/// Uses maximum resolution (2048×2048) with model-specific per-pixel fee.
///
/// # Arguments
/// * `model_info` - Model pricing info from registry
/// * `model_name` - Model name for error messages
///
/// # Returns

/// # Returns
/// * `Ok(AsyncFees)` - Calculated fees (executor_fee only, Phase 1 fees are zero)
/// * `Err(String)` - If model has no image pricing configured
pub fn calculate_image_fees_phase2(
    width: u32,
    height: u32,
    ux: OutputUxParams,
    model_info: &ModelInfo,
    model_name: &str,
) -> Result<AsyncFees, String> {
    // Validate model has image pricing configured
    if model_info.image_fee_wei_per_pixel == 0 && model_info.image_min_fee_wei == 0 {
        return Err(format!("Image model '{}' has no Phase 2 pricing configured", model_name));
    }

    let executor_fee = image_phase2_execution_fee(width, height, ux, model_info);
    // Validators not paid in Phase 2 (already paid in Phase 1)
    Ok(AsyncFees::new(executor_fee, U256::ZERO, U256::ZERO))
}

// ============================================================================
// AUDIO CALL (0x0819) PRICING FUNCTIONS

/// # Returns
/// * `Ok(U256)` - Escrow amount in wei
/// * `Err(String)` - If model pricing is invalid
pub fn video_escrow_lockup(model_info: &ModelInfo, model_name: &str) -> Result<U256, String> {
    // Validate model has video pricing configured
    if model_info.video_fee_wei_per_pixel_second == 0 && model_info.video_base_fee_wei == 0 {
        return Err(format!(
            "Video model '{}' has no pricing configured (fee_per_pixel_second=0, base_fee=0)",
            model_name
        ));
    }

    // Worst case: max resolution at max duration
    let max_pixels = (VIDEO_MAX_WIDTH as u64) * (VIDEO_MAX_HEIGHT as u64);
    let max_duration_sec = VIDEO_MAX_DURATION_MS / 1000;

    // Calculate pixel-second fee using model-specific pricing
    let pixel_seconds = (max_pixels as u128) * (max_duration_sec as u128);
    let pixel_second_fee =
        U256::from(model_info.video_fee_wei_per_pixel_second) * U256::from(pixel_seconds);
    let base_fee = U256::from(model_info.video_base_fee_wei) + pixel_second_fee;
